  // =========================================================================
  // cond_5
  // =========================================================================
  test("cond_5") {
    assertCompresses(
      input = """if (some_condition()) {
            if (some_other_condition()) {
                do_something();
            } else {
                alternate();
            }
        } else {
            alternate();
        }

        if (some_condition()) {
            if (some_other_condition()) {
                do_something();
            }
        }""".stripMargin.trim,
      expected = """some_condition() && some_other_condition() ? do_something() : alternate();
        if (some_condition() && some_other_condition()) do_something()""".stripMargin.trim,
      options = AllOff.copy(
        conditionals = true,
        expression = true
      )
    )
  }

  // =========================================================================
  // dead_code_const_annotation_regex
  // =========================================================================
  test("dead_code_const_annotation_regex") {
    assertCompresses(
      input = """var unused;
        // @constraint this shouldn't be a constant
        var CONST_FOO_ANN = false;
        if (CONST_FOO_ANN) {
            console.log("reachable");
        }""".stripMargin.trim,
      expected = """var unused;
        var CONST_FOO_ANN = !1;
        if (CONST_FOO_ANN) console.log('reachable')""".stripMargin.trim,
      options = AllOff.copy(
        booleans = true,
        conditionals = true,
        deadCode = true,
        evaluate = true,
        expression = true,
        loops = true
      )
    )
  }

